import{c as a,Q as t,j as i,m as o}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"ADR-019 — JSON schema validation on PR via ajv","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-019.md","filePath":"adr/ADR-019.md"}'),n={name:"adr/ADR-019.md"};function s(r,e,c,d,l,h){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-019-—-json-schema-validation-on-pr-via-ajv" tabindex="-1">ADR-019 — JSON schema validation on PR via ajv <a class="header-anchor" href="#adr-019-—-json-schema-validation-on-pr-via-ajv" aria-label="Permalink to &quot;ADR-019 — JSON schema validation on PR via ajv&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 TA anchor · §stack · §contracts</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Mission data lives in JSON files editable by contributors without JavaScript knowledge. A malformed mission file (missing required field, wrong type) currently fails silently at runtime. At production scale with external contributors, this needs to fail loudly at PR time.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>JSON schema validation runs in CI on every PR that touches <code>data/</code>. The validator is <code>ajv</code> (Another JSON Schema Validator) — a Node library, no external service. A JSON Schema file at <code>data/schemas/mission.schema.json</code> defines the required shape. The CI step fails if any mission file does not conform.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p><code>ajv</code> is the standard Node JSON Schema validator — well-maintained, fast, no runtime dependency in the browser. A failed validation produces a clear error message naming the file and field. Combined with the doc-system checks from the guide&#39;s §18 checklist, a contributor&#39;s PR gets mechanical correctness feedback without any human review.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>TypeScript interfaces only</strong> — catches type errors in code but not in JSON files at rest; rejected as sole approach.</li><li><strong>Zod at runtime</strong> — validates at fetch time; errors reach the browser; rejected in favour of catching at PR time.</li><li><strong>Manual review</strong> — does not scale; rejected.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: malformed mission files never reach main; contributor feedback is immediate and specific; schema is documentation. Negative: schema must be kept in sync with the data client&#39;s TypeScript interfaces (two sources of truth for the same shape — mitigated by generating one from the other via <code>ts-json-schema-generator</code>).</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p><code>data/schemas/mission.schema.json</code> defines required fields and types. <code>scripts/validate-data.ts</code> runs <code>ajv</code> against all files in <code>data/missions/</code>. CI step: <code>npx tsx scripts/validate-data.ts</code>. Runs on PR and on push to main.</p>',14)])])}const p=a(n,[["render",s]]);export{u as __pageData,p as default};
